37→    private fun fetchPrompts() {
38→        launch {
39→            if (!networkUtilsWrapper.isNetworkAvailable()) {
40→                _uiStateFlow.update { UiState.NetworkError }
41→                return@launch
42→            }
43→
44→            _uiStateFlow.update { UiState.Loading }
45→
46→            fetchBloggingPromptsList.execute()
47→                .onSuccess { prompts ->
48→                    _uiStateFlow.update { UiState.Content(prompts.map(itemModelMapper::toUiModel)) }
49→                }
50→                .onFailure {
51→                    _uiStateFlow.update { UiState.FetchError }
52→                }
53→        }
54→    }
